+fn parse_rollup_payload(payload: &str) -> std::result::Result<Vec<AtcRollupRow>, DbError> {
+    serde_json::from_str(payload)
+        .map_err(|e| DbError::Internal(format!("restore rollups deserialize: {e}")))
+}
