+fn restore_atc_rollups_from_payload(
+    conn: &crate::CanonicalDbConn,
+    payload: &str,
+    now_micros: i64,
+) -> std::result::Result<usize, DbError> {
+    let rollups = parse_rollup_payload(payload)?;
+    let mut restored = 0usize;
+    for row in &rollups {
